import { NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';

export async function GET(req: Request, props: { params: Promise<{ id: string }> }) {
    const params = await props.params;
    const { searchParams } = new URL(req.url);
    const name = searchParams.get('name');
    const { id: testId } = params;

    if (!name) return NextResponse.json({ error: 'Name required' }, { status: 400 });

    try {
        const user = await prisma.user.findUnique({ where: { username: name } });
        if (!user) return NextResponse.json({ error: 'User not found' }, { status: 404 });

        const attempt = await prisma.attempt.findFirst({
            where: { userId: user.id, testId },
            include: {
                test: {
                    include: {
                        questions: {
                            orderBy: { number: 'asc' }
                        }
                    }
                }
            }
        });

        if (!attempt) return NextResponse.json({ error: 'Attempt not found' }, { status: 404 });

        if (!attempt.test.showResults) {
            return NextResponse.json({ error: 'Results are not released yet' }, { status: 403 });
        }

        // Parse answers
        const studentAnswers = JSON.parse(attempt.answers);

        // Construct response with full analysis
        const analysis = attempt.test.questions.map(q => ({
            id: q.id,
            number: q.number,
            text: q.text,
            options: q.options, // JSON string
            correctAnswer: q.correctAnswer,
            studentAnswer: studentAnswers[q.id],
            isCorrect: studentAnswers[q.id] === q.correctAnswer
        }));

        return NextResponse.json({
            testTitle: attempt.test.title,
            score: attempt.score,
            totalQuestions: attempt.test.questions.length,
            analysis
        });

    } catch (error) {
        console.error(error);
        return NextResponse.json({ error: 'Failed to fetch results' }, { status: 500 });
    }
}
